const supportedLocales = Object.keys(resources);
/** Map bare language codes to our regional catalogs when we only ship one variant. */ const languageFallbacks = {
    pt: "pt-BR",
    zh: "zh-CN"
};
/** Full-tag fallbacks for script/region variants not shipped as catalogs. */ const tagFallbacks = {
    "zh-hans": "zh-CN",
    "zh-hant": "zh-TW",
    "zh-hk": "zh-TW",
    "zh-mo": "zh-TW"
};
function resolveLocale(languageTag) {
    if (!languageTag) return "en";
    const normalized = languageTag.replaceAll("_", "-");
    const lower = normalized.toLowerCase();
    // Exact match (case-insensitive), e.g. pt-BR / zh-CN
    const exact = supportedLocales.find((locale)=>locale.toLowerCase() === lower);
    if (exact) return exact;
    const tagFallback = tagFallbacks[lower];
    if (tagFallback) return tagFallback;
    const language = lower.split("-")[0] ?? lower;
    // Exact language match, e.g. es, fr, ja
    if (language in resources) {
        return language;
    }
    // Regional fallback, e.g. pt → pt-BR, zh → zh-CN
    const fallback = languageFallbacks[language];
    if (fallback) return fallback;
    return "en";
}
